// ❌ BAD - accessing struct field without checking zero initialization
struct ShippingAddress { public string Street; public int PostalCode; }
ShippingAddress addr = new ShippingAddress();
Console.WriteLine(addr.Street.Length); // NullReferenceException - Street is null

// ✅ GOOD - check before use or initialize explicitly
ShippingAddress addr2 = new ShippingAddress { Street = "Unknown", PostalCode = 0 };
Console.WriteLine(addr2.Street.Length); // 7

// ❌ BAD - deferred query sees later mutations
var pendingOrders = orderRepository.GetAll();
var highValue = pendingOrders.Where(o => o.Total > 1000); // deferred
pendingOrders.Add(new Order { Total = 5000 }); // added after query definition
foreach (var o in highValue) Process(o); // includes the new 5000 order

// ✅ GOOD - snapshot at the right moment
var highValue2 = pendingOrders.Where(o => o.Total > 1000).ToList();
pendingOrders.Add(new Order { Total = 5000 }); // does NOT affect highValue2
foreach (var o in highValue2) Process(o); // only orders present at query time

// ❌ BAD - expecting value type to be modified without ref
void ApplyDiscount(decimal price)
{
    price = price * 0.9m; // modifies local copy only
}
decimal orderTotal = 100m;
ApplyDiscount(orderTotal);
Console.WriteLine(orderTotal); // 100 - unchanged

// ✅ GOOD - use ref to modify the caller's variable
void ApplyDiscount(ref decimal price)
{
    price = price * 0.9m;
}
ApplyDiscount(ref orderTotal);
Console.WriteLine(orderTotal); // 90

// ❌ BAD - one failing handler silently prevents others from running
Action onOrderShipped = () => SendConfirmationEmail();
onOrderShipped += () => throw new SmtpException(); // this one fails
onOrderShipped += () => UpdateInventory(); // this never runs if above throws
try { onOrderShipped(); } catch { LogError(); }
// UpdateInventory is skipped silently - inventory not updated

// ✅ GOOD - invoke each handler independently
foreach (Action handler in onOrderShipped.GetInvocationList())
{
    try { handler(); }
    catch (Exception ex) { LogError(ex); }
}
// All handlers run; failures are logged per handler

// ❌ BAD - non-virtual method; polymorphism does not work
class NotificationSender { public void Send() => Console.WriteLine("base"); }
class SmsNotificationSender : NotificationSender { public void Send() => Console.WriteLine("sms"); }

NotificationSender sender = new SmsNotificationSender();
sender.Send(); // prints "base" - wrong

// ✅ GOOD - virtual + override enables correct polymorphic dispatch
class NotificationSender { public virtual void Send() => Console.WriteLine("base"); }
class SmsNotificationSender : NotificationSender { public override void Send() => Console.WriteLine("sms"); }

NotificationSender sender2 = new SmsNotificationSender();
sender2.Send(); // prints "sms"
